#include<bits/stdc++.h>
using namespace  std;
int a[105][105];
int b[10005];
int n,m,ans=0;
int main(){
    cin>>n>>m;
    for(int i=1;i<=m;i++) cin>>b[i];
    for(int i=1;i<=n;i++) for(int j=1;j<=n;j++) cin>>a[i][j];
    for(int k=1;k<=n;k++) for(int i=1;i<=n;i++) for(int j=1;j<=n;j++) a[i][j]=min(a[i][j],a[i][k]+a[k][j]);
    for(int i=1;i<=m;i++) ans+=a[b[i-1]][b[i]];
    cout<<ans;
}
